module accu
(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output valid_out,
    output [9:0] data_out
);

reg [1:0] cnt;
reg valid_in_d;
reg [9:0] sum;
reg [9:0] data_out_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) valid_in_d <= 1'b0;
    else if (valid_in) valid_in_d <= 1'b1;
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) cnt <= 2'b0;
    else if (valid_in) begin
        if (cnt == 2'b11) cnt <= 2'b0;
        else cnt <= cnt + 1;
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) sum <= 10'b0;
    else if (valid_in) sum <= 0;
    else if (valid_in_d) sum <= sum + data_in;
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) data_out_reg <= 10'b0;
    else if (valid_in_d) data_out_reg <= sum;
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) valid_out <= 1'b0;
    else if (valid_in_d) valid_out <= 1'b1;
    else valid_out <= 1'b0;
end

assign data_out = data_out_reg;

endmodule
